PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?monarch ?monarchLabel
WHERE {
  ?monarch wdt:P31 wd:Q5 ;
           p:P39 ?position .
  ?position ps:P39 wd:Q110324075 ;
          pq:P580 ?startTime ;
          pq:P582 ?endTime .
  FILTER (?startTime <= "1756-12-31T23:59:59Z"^^xsd:dateTime)
  FILTER (?endTime >= "1756-01-01T00:00:00Z"^^xsd:dateTime)
  OPTIONAL {
    ?monarch rdfs:label ?monarchLabel .
    FILTER (lang(?monarchLabel) = "en")
  }
}
LIMIT 1

